INSERT INTO sys_role_menu (role_id, menu_id) SELECT r.role_id, m.menu_id FROM sys_role r CROSS JOIN sys_menu m WHERE r.role_key = 'erp_purchaser' AND (m.perms LIKE 'erp:销售:%' OR m.perms LIKE 'erp:purchase:%' OR m.perms LIKE 'erp:stock:%' OR m.perms LIKE 'erp:report:%') AND NOT EXISTS (SELECT 1 FROM sys_role_menu rm WHERE rm.role_id = r.role_id AND rm.menu_id = m.menu_id);
INSERT INTO sys_role_menu (role_id, menu_id) SELECT r.role_id, m.menu_id FROM sys_role r CROSS JOIN sys_menu m WHERE r.role_key = 'erp_qc' AND (m.perms LIKE 'erp:bom:%' OR m.perms LIKE 'erp:quality:%' OR m.perms LIKE 'erp:defect:%' OR m.perms LIKE 'erp:process:%' OR m.perms LIKE 'erp:outsource:%' OR m.perms LIKE 'erp:report:%') AND NOT EXISTS (SELECT 1 FROM sys_role_menu rm WHERE rm.role_id = r.role_id AND rm.menu_id = m.menu_id);
INSERT INTO sys_role_menu (role_id, menu_id) SELECT r.role_id, m.menu_id FROM sys_role r CROSS JOIN sys_menu m WHERE r.role_key = 'erp_outsource' AND (m.perms LIKE 'erp:outsource:%' OR m.perms LIKE 'erp:report:%') AND NOT EXISTS (SELECT 1 FROM sys_role_menu rm WHERE rm.role_id = r.role_id AND rm.menu_id = m.menu_id);
INSERT INTO sys_role_menu (role_id, menu_id) SELECT r.role_id, m.menu_id FROM sys_role r CROSS JOIN sys_menu m WHERE r.role_key = 'erp_pmc' AND (m.perms LIKE 'erp:produce:%' OR m.perms LIKE 'erp:gantt:%' OR m.perms LIKE 'erp:report:%') AND NOT EXISTS (SELECT 1 FROM sys_role_menu rm WHERE rm.role_id = r.role_id AND rm.menu_id = m.menu_id);
