INSERT INTO sys_role_menu (role_id, menu_id) SELECT r.role_id, m.menu_id FROM sys_role r CROSS JOIN sys_menu m WHERE r.role_key = 'erp_sample' AND (m.perms LIKE 'erp:notice:%' OR m.perms LIKE 'erp:bom:%' OR m.perms LIKE 'erp:report:%') AND NOT EXISTS (SELECT 1 FROM sys_role_menu rm WHERE rm.role_id = r.role_id AND rm.menu_id = m.menu_id);
INSERT INTO sys_role_menu (role_id, menu_id) SELECT r.role_id, m.menu_id FROM sys_role r CROSS JOIN sys_menu m WHERE r.role_key = 'erp_outsource_vendor' AND (m.perms LIKE 'erp:outsource:%' OR m.perms LIKE 'erp:report:%') AND m.perms NOT LIKE '%:add%' AND m.perms NOT LIKE '%:edit%' AND m.perms NOT LIKE '%:remove%' AND NOT EXISTS (SELECT 1 FROM sys_role_menu rm WHERE rm.role_id = r.role_id AND rm.menu_id = m.menu_id);
INSERT INTO sys_role_menu (role_id, menu_id) SELECT r.role_id, m.menu_id FROM sys_role r CROSS JOIN sys_menu m WHERE r.role_key = 'erp_inspection_company' AND (m.perms LIKE 'erp:quality:%' OR m.perms LIKE 'erp:report:%') AND m.perms NOT LIKE '%:add%' AND m.perms NOT LIKE '%:edit%' AND m.perms NOT LIKE '%:remove%' AND NOT EXISTS (SELECT 1 FROM sys_role_menu rm WHERE rm.role_id = r.role_id AND rm.menu_id = m.menu_id);
INSERT INTO sys_role_menu (role_id, menu_id) SELECT r.role_id, m.menu_id FROM sys_role r CROSS JOIN sys_menu m WHERE r.role_key = 'erp_management' AND m.perms LIKE 'erp:%' AND m.menu_type = 'C' AND NOT EXISTS (SELECT 1 FROM sys_role_menu rm WHERE rm.role_id = r.role_id AND rm.menu_id = m.menu_id);
